import type { Metadata } from 'next';
import Link from 'next/link';
import { notFound } from 'next/navigation';
import type { JsonPlaceholderComment, JsonPlaceholderPost } from '../../../lib/blog';
import {
  isJsonPlaceholderCommentArray,
  isJsonPlaceholderPost,
} from '../../../lib/blog';

export const revalidate = 300;

interface BlogPostPageProps {
  params: Promise<{
    id: string;
  }>;
}

interface CommentListProps {
  comments: JsonPlaceholderComment[];
}

export async function generateStaticParams(): Promise<Array<{ id: string }>> {
  const postsResponse = await fetch('https://jsonplaceholder.typicode.com/posts');
  const postsData: unknown = await postsResponse.json();

  if (!Array.isArray(postsData)) {
    return [];
  }

  return postsData
    .filter(isJsonPlaceholderPost)
    .slice(0, 10)
    .map((post) => ({
      id: post.id.toString(),
    }));
}

export async function generateMetadata({
  params,
}: BlogPostPageProps): Promise<Metadata> {
  const { id } = await params;
  const post = await getPost(id);

  if (!post) {
    return {
      title: 'Post not found',
    };
  }

  return {
    title: post.title,
    description: post.body.substring(0, 160),
    openGraph: {
      title: post.title,
      description: post.body.substring(0, 160),
    },
  };
}

export default async function BlogPostPage({ params }: BlogPostPageProps) {
  const { id } = await params;
  const [post, comments] = await Promise.all([getPost(id), getComments(id)]);

  if (!post || !comments) {
    notFound();
  }

  return (
    <article>
      <Link className="button-link" href="/blog">
        ← Back
      </Link>

      <h1>{post.title}</h1>
      <p>{post.body}</p>

      <h2>Comments ({comments.length})</h2>
      <div className="comments">
        {comments.map((comment) => (
          <div key={comment.id} className="comment">
            <h3>{comment.name}</h3>
            <p>{comment.body}</p>
            <small>By: {comment.email}</small>
          </div>
        ))}
      </div>
    </article>
  );
}

async function getPost(id: string): Promise<JsonPlaceholderPost | null> {
  const response = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}`, {
    next: { revalidate },
  });
  const data: unknown = await response.json();

  if (!isJsonPlaceholderPost(data)) {
    return null;
  }

  return data;
}

async function getComments(id: string): Promise<JsonPlaceholderComment[] | null> {
  const response = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`, {
    next: { revalidate },
  });
  const data: unknown = await response.json();

  if (!isJsonPlaceholderCommentArray(data)) {
    return null;
  }

  return data;
}


