import { NextResponse } from 'next/server';
import type {
  ApiErrorResponse,
  BlogPostRecord,
  BlogPostWithTimestamps,
  CreatePostInput,
} from '../../../../lib/blog';

type PostRouteContext = {
  params: Promise<{
    id: string;
  }>;
};

const posts: BlogPostRecord[] = [
  { id: 1, title: 'First Post', content: 'This is the first post' },
  { id: 2, title: 'Second Post', content: 'This is the second post' },
];

export async function GET(_request: Request, context: PostRouteContext) {
  const { id } = await context.params;
  const postId = Number.parseInt(id, 10);
  const post = posts.find((entry) => entry.id === postId);

  if (!post) {
    return NextResponse.json<ApiErrorResponse>(
      { error: 'Post not found' },
      { status: 404 }
    );
  }

  return NextResponse.json<BlogPostRecord>(post, { status: 200 });
}

export async function PUT(request: Request, context: PostRouteContext) {
  const { id } = await context.params;
  const postId = Number.parseInt(id, 10);
  const body: unknown = await request.json();

  const updates = isCreatePostInput(body) ? body : {};
  const existingPost = posts.find((entry) => entry.id === postId);

  if (!existingPost) {
    return NextResponse.json<ApiErrorResponse>(
      { error: 'Post not found' },
      { status: 404 }
    );
  }

  const updatedPost: BlogPostWithTimestamps = {
    id: postId,
    title: updates.title ?? existingPost.title,
    content: updates.content ?? existingPost.content,
    updatedAt: new Date().toISOString(),
  };

  const postIndex = posts.findIndex((entry) => entry.id === postId);
  posts[postIndex] = {
    id: updatedPost.id,
    title: updatedPost.title,
    content: updatedPost.content,
  };

  return NextResponse.json<BlogPostWithTimestamps>(updatedPost, { status: 200 });
}

export async function DELETE(_request: Request, context: PostRouteContext) {
  const { id } = await context.params;
  const postId = Number.parseInt(id, 10);
  const postIndex = posts.findIndex((entry) => entry.id === postId);

  if (postIndex === -1) {
    return NextResponse.json<ApiErrorResponse>(
      { error: 'Post not found' },
      { status: 404 }
    );
  }

  posts.splice(postIndex, 1);

  return NextResponse.json<{ message: string }>(
    { message: `Post ${id} deleted successfully` },
    { status: 200 }
  );
}

function isCreatePostInput(value: unknown): value is CreatePostInput {
  if (typeof value !== 'object' || value === null) {
    return false;
  }

  const candidate = value as Partial<CreatePostInput>;
  return typeof candidate.title === 'string' && typeof candidate.content === 'string';
}


